/**
 * Integration tests for the knotgraph ingest paragon.
 *
 * Closes the end-to-end loop: app vomits bytes → wire settles →
 * knotgraph-shaped blocks emerge, each passing tenant isolation and
 * bit-equal across region-parallel pipelines.
 *
 * Witnesses both the prismatic-refraction crown theorem
 * (`THM-WIRE-TO-STORAGE-IS-SOUND`) and knotgraph's
 * `Tenancy/TenantIsolation` + `Race/EncodingRaceDeterminism` at this
 * module's seam.
 */

import { describe, expect, it } from '@a0n/gnosis/test';
import { createRawStream } from '../prismatic-refraction';
import {
  blockBelongsToTenant,
  blocksDimsEqual,
  ingestToKnotgraph,
  KNOTGRAPH_DIMS,
  shardToBlock,
  type IngestContext,
  type TenantId,
} from '../prismatic-refraction-knotgraph';

// ─── Seeded PRNG ─────────────────────────────────────────────────────

function lcg(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (Math.imul(s, 1664525) + 1013904223) >>> 0;
    return s;
  };
}

function randomBytes(seed: number, n: number): number[] {
  const rng = lcg(seed);
  const out = new Array<number>(n);
  for (let i = 0; i < n; i++) out[i] = rng() & 0xff;
  return out;
}

// ─── Fixtures ────────────────────────────────────────────────────────

const testTenant: TenantId = { hi: 0x1234_5678, lo: 0x9abc_def0 };

function ctxFor(tenant: TenantId, seed: number): IngestContext {
  return {
    tenant,
    typeTag: seed * 1_000_037,
    schemaKnotHash: seed * 2_000_011,
    provenanceDid: seed,
    freshnessClock: seed * 100,
  };
}

// ─── Tests ───────────────────────────────────────────────────────────

describe('Prismatic Refraction → Knotgraph Ingest', () => {
  describe('Block shape (app zone 38-53)', () => {
    it('every block has exactly 54 dims', () => {
      const stream = createRawStream(randomBytes(1, 1024));
      const { blocks } = ingestToKnotgraph(stream, 8, ctxFor(testTenant, 1));
      for (const b of blocks) {
        expect(b.dims.length).toBe(54);
      }
    });

    it('dims 0-37 (knotchain core) are left at zero for seal-phase', () => {
      const stream = createRawStream(randomBytes(2, 512));
      const { blocks } = ingestToKnotgraph(stream, 4, ctxFor(testTenant, 2));
      for (const b of blocks) {
        for (let i = 0; i < 38; i++) {
          expect(b.dims[i]).toBe(0);
        }
      }
    });

    it('REGION_ID (dim 40) = shard.laneId — lane IS the sub-region', () => {
      const stream = createRawStream(randomBytes(3, 2048));
      const { blocks, witness } = ingestToKnotgraph(stream, 16, ctxFor(testTenant, 3));
      expect(blocks.length).toBe(witness.settled.length);
      for (let i = 0; i < blocks.length; i++) {
        expect(blocks[i]!.dims[KNOTGRAPH_DIMS.REGION_ID]).toBe(
          witness.settled[i]!.laneId,
        );
      }
    });

    it('FIELD_0 (payload length) totals to input byte count', () => {
      for (let seed = 1; seed <= 10; seed++) {
        const n = 512 + (seed * 37) % 1024;
        const stream = createRawStream(randomBytes(seed, n));
        const { blocks } = ingestToKnotgraph(stream, 8, ctxFor(testTenant, seed));
        let total = 0;
        for (const b of blocks) total += b.dims[KNOTGRAPH_DIMS.FIELD_0]!;
        expect(total).toBe(n);
      }
    });
  });

  describe('Tenant isolation (knotgraph TenantIsolation.lean seam)', () => {
    it('every block passes blockBelongsToTenant for the caller', () => {
      for (let seed = 1; seed <= 20; seed++) {
        const stream = createRawStream(randomBytes(seed, 1024));
        const ctx = ctxFor(testTenant, seed);
        const { blocks, tenantScopeHoldsForAll } = ingestToKnotgraph(stream, 8, ctx);
        expect(tenantScopeHoldsForAll).toBe(true);
        for (const b of blocks) {
          expect(blockBelongsToTenant(b, testTenant)).toBe(true);
        }
      }
    });

    it('blocks do NOT pass tenant check for a different tenant', () => {
      const stream = createRawStream(randomBytes(1, 256));
      const { blocks } = ingestToKnotgraph(stream, 4, ctxFor(testTenant, 1));
      const otherTenant: TenantId = { hi: 0xdead_beef, lo: 0xcafe_babe };
      for (const b of blocks) {
        expect(blockBelongsToTenant(b, otherTenant)).toBe(false);
      }
    });
  });

  describe('Region-parallel determinism (knotgraph race_deterministic seam)', () => {
    it('two independent ingests over same inputs produce bit-equal blocks', () => {
      for (let seed = 1; seed <= 20; seed++) {
        const stream = createRawStream(randomBytes(seed, 4096));
        const ctx = ctxFor(testTenant, seed);
        const a = ingestToKnotgraph(stream, 8, ctx);
        const b = ingestToKnotgraph(stream, 8, ctx);
        expect(a.blocks.length).toBe(b.blocks.length);
        for (let i = 0; i < a.blocks.length; i++) {
          expect(blocksDimsEqual(a.blocks[i]!, b.blocks[i]!)).toBe(true);
        }
      }
    });

    it('shardToBlock is a pure function of (shard, ctx)', () => {
      const shard = { laneId: 3, phase: 42, payload: [1, 2, 3, 4] as const };
      const ctx = ctxFor(testTenant, 1);
      const b1 = shardToBlock(shard, ctx);
      const b2 = shardToBlock(shard, ctx);
      expect(blocksDimsEqual(b1, b2)).toBe(true);
    });

    it('changing any ctx field changes the block', () => {
      const shard = { laneId: 1, phase: 0, payload: [10, 20] as const };
      const base = shardToBlock(shard, ctxFor(testTenant, 1));
      const otherType = shardToBlock(shard, {
        ...ctxFor(testTenant, 1),
        typeTag: 999,
      });
      const otherSchema = shardToBlock(shard, {
        ...ctxFor(testTenant, 1),
        schemaKnotHash: 888,
      });
      expect(blocksDimsEqual(base, otherType)).toBe(false);
      expect(blocksDimsEqual(base, otherSchema)).toBe(false);
    });
  });

  describe('Content addressing (ENTITY_ID)', () => {
    it('same payload → same ENTITY_ID, different payload → different ENTITY_ID', () => {
      const ctx = ctxFor(testTenant, 1);
      const shardA = { laneId: 1, phase: 0, payload: [1, 2, 3] as const };
      const shardB = { laneId: 1, phase: 0, payload: [1, 2, 3] as const };
      const shardC = { laneId: 1, phase: 0, payload: [1, 2, 4] as const };
      const bA = shardToBlock(shardA, ctx);
      const bB = shardToBlock(shardB, ctx);
      const bC = shardToBlock(shardC, ctx);
      expect(bA.dims[KNOTGRAPH_DIMS.ENTITY_ID]).toBe(bB.dims[KNOTGRAPH_DIMS.ENTITY_ID]);
      expect(bA.dims[KNOTGRAPH_DIMS.ENTITY_ID]).not.toBe(bC.dims[KNOTGRAPH_DIMS.ENTITY_ID]);
    });

    it('ENTITY_ID fits in 48 bits (fp64-safe)', () => {
      for (let seed = 1; seed <= 30; seed++) {
        const payload = randomBytes(seed, 32);
        const b = shardToBlock(
          { laneId: 0, phase: 0, payload },
          ctxFor(testTenant, 1),
        );
        const id = b.dims[KNOTGRAPH_DIMS.ENTITY_ID]!;
        expect(Number.isInteger(id)).toBe(true);
        expect(id).toBeGreaterThanOrEqual(0);
        expect(id).toBeLessThan(2 ** 48);
      }
    });
  });

  describe('End-to-end soundness (crown seam)', () => {
    it('every ingest preserves the prismatic-refraction crown witness', () => {
      for (let seed = 1; seed <= 20; seed++) {
        const n = 256 + (seed * 71) % 2048;
        const stream = createRawStream(randomBytes(seed, n));
        for (const k of [1, 4, 8, 16]) {
          const result = ingestToKnotgraph(stream, k, ctxFor(testTenant, seed));
          expect(result.witness.lanesBounded).toBe(true);
          expect(result.witness.payloadPreserved).toBe(true);
          expect(result.witness.totalBytes).toBe(n);
          expect(result.blocks.length).toBeLessThanOrEqual(k);
          expect(result.totalIngestedBytes).toBe(n);
          expect(result.tenantScopeHoldsForAll).toBe(true);
        }
      }
    });

    it('empty stream produces zero blocks, soundness still holds', () => {
      const stream = createRawStream([]);
      const r = ingestToKnotgraph(stream, 8, ctxFor(testTenant, 1));
      expect(r.blocks.length).toBe(0);
      expect(r.totalIngestedBytes).toBe(0);
      expect(r.witness.lanesBounded).toBe(true);
      expect(r.witness.payloadPreserved).toBe(true);
      expect(r.tenantScopeHoldsForAll).toBe(true);
    });

    it('rejects k > 16 (knotgraph app-zone width)', () => {
      const stream = createRawStream([1, 2, 3]);
      expect(() =>
        ingestToKnotgraph(stream, 17, ctxFor(testTenant, 1)),
      ).toThrow();
    });
  });
});
